scwin.sbm_mhnoLoading_submitdone = async function (e) {
  if (ds_hmhno.getRowCount() == 0) {
    if (scwin.statusFlag != "C") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["House No"]);
    }
    ds_hmhno.insertRow();
    ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", "NONE");
    ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", "NONE");
    acb_hhpcgb.setSelectedIndex(0);
  }
  if (scwin.statusFlag == "C") {
    ds_hmhno.removeAll();
    ds_hmhno.insertRow();
    ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", "NONE");
    ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", "NONE");
    acb_hhpcgb.setSelectedIndex(0);
  }
  if (scwin.mhnoFlag == "1") {
    scwin.f_Retrieve();
    scwin.mhnoFlag = "0";
  }
};
